python3 - <<'PY'
from pathlib import Path
import re, hashlib
root = Path('shaders/escape_time_family/mandelbrot_variants')
pattern = re.compile(r'^(vec[234]|float|int|bool)\s+(linearToSRGB|palette|cmul|cdiv|cinv|csqrt|ccos|csin|cx_mul|cx_exp)\s*\([^)]*\)\s*\{', re.M)
for name in ['linearToSRGB', 'palette', 'cmul', 'cdiv']:
    groups = {}
    for path in sorted(root.rglob('*.frag')):
        text = path.read_text()
        m = re.search(r'^(vec[234]|float|int|bool)\s+' + re.escape(name) + r'\s*\([^)]*\)\s*\{', text, re.M)
        if not m:
            continue
        start = m.start()
        depth = 0
        end = None
        for i, ch in enumerate(text[start:], start):
            if ch == '{':
                depth += 1
            elif ch == '}':
                depth -= 1
                if depth == 0:
                    end = i + 1
                    break
        body = text[start:end]
        norm = re.sub(r'\s+', ' ', body).strip()
        key = hashlib.sha1(norm.encode()).hexdigest()[:8]
        groups.setdefault(key, []).append(str(path.relative_to(root)))
    print(f'{name}: {sum(len(v) for v in groups.values())} definitions, {len(groups)} unique bodies')
    for key, paths in sorted(groups.items(), key=lambda kv: (-len(kv[1]), kv[0])):
        print(f'  {key}: {len(paths)} files')
        for p in paths:
            print(f'    - {p}')
